return-response.set-body:
@{
                return JObject.FromObject(new {
                    resource = "{{APIMGatewayURL}}/mcp",
                    authorization_servers = new[] { "{{McpOAuthBaseUrl}}" },
                    scopes_supported = new[] { "{{McpScope}}" },
                    bearer_methods_supported = new[] { "header" }
                }).ToString();
            }
